using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Text.Json;

namespace McpStdioServer;

[McpServerToolType]
public sealed class ApiFetchTool
{
    private readonly IHttpClientFactory _httpClientFactory;

    public ApiFetchTool(IHttpClientFactory httpClientFactory)
    {
        _httpClientFactory = httpClientFactory;
    }

    [McpServerTool("fetch_api_data"),
     Description("Fetches data from an external REST API endpoint and returns the JSON response.")]
    public async Task<string> FetchApiDataAsync(
        [Description("The relative API path to fetch (e.g. \"posts/1\" or \"users\").")] string path,
        CancellationToken cancellationToken = default)
    {
        using var client = _httpClientFactory.CreateClient("ExternalApi");
        using var response = await client.GetAsync(path, cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync(cancellationToken);

        // Pretty-print for readability.
        using var doc = JsonDocument.Parse(json);
        return JsonSerializer.Serialize(doc, new JsonSerializerOptions { WriteIndented = true });
    }
}

using ModelContextProtocol.Server;
using System.ComponentModel;

namespace McpStdioServer;

[McpServerPromptType]
public sealed class SummarizePrompt
{
    [McpServerPrompt("summarize"),
     Description("Generates a prompt that asks an LLM to summarize the given text.")]
    public static IList<Microsoft.Extensions.AI.ChatMessage> Summarize(
        [Description("The text content to summarize.")] string text,
        [Description("Optional desired length: 'brief', 'detailed', or 'bullet-points'. Defaults to 'brief'.")]
        string style = "brief")
    {
        var systemInstruction = style.ToLowerInvariant() switch
        {
            "detailed" => "Provide a thorough, multi-paragraph summary that preserves key details.",
            "bullet-points" => "Summarize the text as a concise bulleted list of key points.",
            _ => "Provide a concise one-paragraph summary."
        };

        return
        [
            new(Microsoft.Extensions.AI.ChatRole.System, systemInstruction),
            new(Microsoft.Extensions.AI.ChatRole.User, $"Please summarize the following text:\n\n{text}")
        ];
    }
}

